# model_router.py — route traffic between model versions during upgrade

import random
from enum import Enum

class ModelVersion(str, Enum):
    CURRENT = "gpt-4o-2024-11-20"
    CANARY  = "gpt-4o-2025-01-15"

class ModelRouter:
    def __init__(self, canary_pct: float = 0.0):
        # canary_pct: 0.0 = 100% current; 0.1 = 10% canary; 1.0 = 100% canary
        self.canary_pct = canary_pct

    def select(self, user_id: str | None = None) -> str:
        # Sticky routing: same user always sees the same model during canary
        # This prevents a user from seeing inconsistent behavior across requests
        if user_id:
            # Deterministic based on user_id hash
            pct = (hash(user_id) % 1000) / 1000.0
            return (ModelVersion.CANARY if pct < self.canary_pct
                    else ModelVersion.CURRENT)
        # Stateless: random routing
        return (ModelVersion.CANARY if random.random() < self.canary_pct
                else ModelVersion.CURRENT)

    def update_canary_pct(self, new_pct: float) -> None:
        self.canary_pct = max(0.0, min(1.0, new_pct))
